function initNavigation(){const e=document.querySelector(".hamburger"),t=document.querySelector(".nav-menu");e&&t&&(e.addEventListener("click",()=>{const a=t.classList.toggle("active");e.classList.toggle("is-active",a),e.setAttribute("aria-expanded",a)}),t.querySelectorAll(".nav-link").forEach(a=>{a.addEventListener("click",()=>{t.classList.remove("active"),e.classList.remove("is-active")})}))}function initStats(){document.querySelectorAll(".stat-number[data-count]").forEach(e=>{animateCounter(e,parseInt(e.dataset.count,10))})}function animateCounter(e,t){const a=performance.now();requestAnimationFrame(function n(s){const o=Math.min((s-a)/1200,1),c=1-Math.pow(1-o,3);e.textContent=Math.floor(c*t)+(1===o?"+":""),o<1&&requestAnimationFrame(n)})}async function loadLatestReleases(){const e=document.getElementById("latestReleases");if(e)try{const t=await fetch("data/tracks.json");if(!t.ok)throw new Error("fetch failed");const a=[...(await t.json()).tracks].sort((e,t)=>new Date(t.releaseDate)-new Date(e.releaseDate)).slice(0,6);e.innerHTML=a.map(e=>{const t=new Date(e.releaseDate).toLocaleDateString("fr-FR",{day:"numeric",month:"long",year:"numeric"});return`\n        <div class="release-card">\n          <h3>${escHtml(e.title)}</h3>\n          <p>${escHtml(e.mix)}</p>\n          <p class="release-catalog">${escHtml(e.catalog)}</p>\n          <p class="release-date">${t}</p>\n        </div>`}).join("")}catch(t){e.innerHTML='<p style="color:var(--fg-muted);font-size:.8rem;">Impossible de charger les sorties.</p>',console.warn("loadLatestReleases:",t)}}function escHtml(e){return String(e??"").replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;").replace(/"/g,"&quot;")}document.addEventListener("DOMContentLoaded",()=>{initNavigation(),initStats(),loadLatestReleases()});